import 'package:flutter/material.dart';
class PlaceholderScreen extends StatelessWidget{const PlaceholderScreen(this.title,{super.key});final String title;@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:Text(title)),body:Center(child:Column(mainAxisSize:MainAxisSize.min,children:[Icon(_icon(),size:64,color:Colors.green),const SizedBox(height:16),Text(title,style:Theme.of(context).textTheme.headlineSmall),const SizedBox(height:8),const Text('Connected screen scaffold',style:TextStyle(color:Colors.grey))])));IconData _icon()=>title.contains('Cart')?Icons.shopping_bag_outlined:title.contains('Order')?Icons.receipt_long:Icons.storefront;}
class HomeScreen extends StatelessWidget{const HomeScreen({super.key});static const screens=['Select location','Nearby shops','Shop listing','Product listing','Product details','Multi-shop cart','Checkout','Razorpay payment','Order tracking','My orders','Profile & addresses'];@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('FreshLane'),actions:[IconButton(onPressed:()=>Navigator.pushNamed(context,'/profile'),icon:const Icon(Icons.person_outline))]),body:ListView(padding:const EdgeInsets.all(16),children:[const Text('Everything nearby, one checkout.',style:TextStyle(fontSize:28,fontWeight:FontWeight.w800)),const SizedBox(height:18),...screens.map((s)=>Card(child:ListTile(leading:const Icon(Icons.arrow_outward,color:Colors.green),title:Text(s),onTap:()=>Navigator.push(context,MaterialPageRoute(builder:(_)=>PlaceholderScreen(s)))))]));}
